query:
//DELETE CUSTOM MAPS
MATCH (n)
WHERE ANY(label IN labels(n) WHERE 
    label STARTS WITH 'search_' OR 
    label STARTS WITH 'riskmap_' OR 
    label STARTS WITH 'visibilitytest_' OR 
    label STARTS WITH 'networkmap_'
)
DETACH DELETE n;

// 🧹 EL LIMPIADOR DEFINITIVO: Borra todas las vistas dinámicas de un plumazo
MATCH (n)
WHERE ANY(label IN labels(n) WHERE 
    label STARTS WITH 'search_' OR 
    label STARTS WITH 'riskmap_' OR 
    label STARTS WITH 'visibilitytest_' OR 
    label STARTS WITH 'networkmap_'
)
DETACH DELETE n;

MATCH (n)
WHERE labels(n)[0] STARTS WITH 'networkmap_'
DETACH DELETE n;

MATCH (n)
WHERE labels(n)[0] STARTS WITH 'visibilitytest_'
DETACH DELETE n;

MATCH (n) 
WHERE labels(n)[0] STARTS WITH 'search_' 
DETACH DELETE n;
